interface RelayUserResponse {
	cancelled: boolean;
	selection?: string | string[];
	comment?: string;
	raw?: unknown;
}

interface TeamConfig {
	name: string;
	members: string[];
	source: AgentSource;
	filePath: string;
}

interface AgentRuntimeState {
	runtimeId: string;
	agent: string;
	source: AgentSource;
	mode: AgentDeployMode;
	launchBackend: AgentLaunchBackend;
	cwd: string;
