				theme.fg("toolTitle", theme.bold("deploy_agent ")) +
				theme.fg("accent", context.args.agent || "unknown") +
				theme.fg("muted", ` [${scope} · ${mode} · ${launchBackend}]`);
			const taskLine = taskPreview ? `  ${theme.fg("dim", taskPreview)}` : undefined;
